class Solution {
    public int minDistance(String word1, String word2) {
        return dp(word1, word2, word1.length(), word2.length());
    }

    private int dp(String w1, String w2, int i, int j) {
        if (i == 0) return j; // insert j chars
        if (j == 0) return i; // delete i chars
        if (w1.charAt(i - 1) == w2.charAt(j - 1)) {
            return dp(w1, w2, i - 1, j - 1);
        } else {
            // replace, delete, insert
            int replace = dp(w1, w2, i - 1, j - 1);
            int delete = dp(w1, w2, i - 1, j);
            int insert = dp(w1, w2, i, j - 1);
            return 1 + Math.min(replace, Math.min(delete, insert));
        }
    }
}

class Solution {
    public int minDistance(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] memo = new int[m + 1][n + 1];
        for (int[] row : memo) Arrays.fill(row, -1);
        return dp(word1, word2, m, n, memo);
    }

    private int dp(String w1, String w2, int i, int j, int[][] memo) {
        if (i == 0) return j;
        if (j == 0) return i;
        if (memo[i][j] != -1) return memo[i][j];
        if (w1.charAt(i - 1) == w2.charAt(j - 1)) {
            return memo[i][j] = dp(w1, w2, i - 1, j - 1, memo);
        } else {
            int replace = dp(w1, w2, i - 1, j - 1, memo);
            int delete = dp(w1, w2, i - 1, j, memo);
            int insert = dp(w1, w2, i, j - 1, memo);
            return memo[i][j] = 1 + Math.min(replace, Math.min(delete, insert));
        }
    }
}

class Solution {
    public int minDistance(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] dp = new int[m + 1][n + 1];
        for (int i = 0; i <= m; i++) dp[i][0] = i;
        for (int j = 0; j <= n; j++) dp[0][j] = j;
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (word1.charAt(i - 1) == word2.charAt(j - 1)) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else {
                    dp[i][j] = 1 + Math.min(dp[i - 1][j - 1], Math.min(dp[i - 1][j], dp[i][j - 1]));
                }
            }
        }
        return dp[m][n];
    }
}
